create database if not exists knowledge_pulse;
use knowledge_pulse;

create table if not exists `user` (
                                      `id` bigint primary key auto_increment,
                                      `username` varchar(50) not null unique,
                                      `password` varchar(100) not null,
                                      `email` varchar(100) not null unique,
                                      `avatar` varchar(255) default null,
                                      `nickname` varchar(50) default null,
                                      `role` varchar(20) default 'USER',
                                      `create_time` datetime default current_timestamp,
                                      `update_time` datetime default current_timestamp on update current_timestamp,
                                      index idx_email (`email`)
) engine=InnoDB default charset=utf8mb4;

create table if not exists `note_folder` (
                                             `id` bigint primary key auto_increment,
                                             `user_id` bigint not null,
                                             `name` varchar(100) not null,
                                             `parent_id` bigint default null,
                                             `create_time` datetime default current_timestamp,
                                             `update_time` datetime default current_timestamp on update current_timestamp,
                                             foreign key (`user_id`) references `user`(`id`),
                                             foreign key (`parent_id`) references `note_folder`(`id`)
) engine=InnoDB default charset=utf8mb4;

create table if not exists `note` (
                                      `id` bigint primary key auto_increment,
                                      `user_id` bigint not null,
                                      `folder_id` bigint default null,
                                      `title` varchar(200) not null,
                                      `content` longtext,
                                      `html_content` longtext,
                                      `tags` varchar(500) default null,
                                      `is_public` tinyint(1) default 0,
                                      `share_token` varchar(32) default null,
                                      `share_password` varchar(100) default null,
                                      `daily_note_date` date default null,
                                      `is_deleted` tinyint(1) default 0,
                                      `deleted_time` datetime default null,
                                      `create_time` datetime default current_timestamp,
                                      `update_time` datetime default current_timestamp on update current_timestamp,
                                      fulltext index `ft_search` (`title`, `content`),
                                      index `idx_note_daily` (`daily_note_date`),
                                      index `idx_note_deleted` (`is_deleted`, `deleted_time`),
                                      unique key `uk_note_daily_user_date` (`user_id`, `daily_note_date`),
                                      foreign key (`user_id`) references `user`(`id`),
                                      foreign key (`folder_id`) references `note_folder`(`id`)
) engine=InnoDB default charset=utf8mb4;

create table if not exists `note_tag` (
                                          `id` bigint primary key auto_increment,
                                          `note_id` bigint not null,
                                          `tag_name` varchar(50) not null,
                                          foreign key (`note_id`) references `note`(`id`) on delete cascade
) engine=InnoDB default charset=utf8mb4;

create table if not exists `note_relation` (
                                               `id` bigint primary key auto_increment,
                                               `source_note_id` bigint not null,
                                               `target_note_id` bigint not null,
                                               `relation_type` varchar(20) not null,
                                               `create_time` datetime default current_timestamp,
                                               foreign key (`source_note_id`) references `note`(`id`),
                                               foreign key (`target_note_id`) references `note`(`id`)
) engine=InnoDB default charset=utf8mb4;

create table if not exists `note_version` (
                                              `id` bigint primary key auto_increment,
                                              `note_id` bigint not null,
                                              `version` int not null default 1,
                                              `content_snapshot` longtext not null,
                                              `create_time` datetime default current_timestamp,
                                              foreign key (`note_id`) references `note`(`id`)
) engine=InnoDB default charset=utf8mb4;

create table if not exists `note_collaborator` (
                                                   `id` bigint primary key auto_increment,
                                                   `note_id` bigint not null,
                                                   `user_id` bigint not null,
                                                   `permission` enum('READ', 'EDIT', 'OWNER') not null default 'READ',
                                                   `create_time` datetime default current_timestamp,
                                                   unique key `uk_note_collaborator` (`note_id`, `user_id`),
                                                   foreign key (`note_id`) references `note`(`id`) on delete cascade,
                                                   foreign key (`user_id`) references `user`(`id`)
) engine=InnoDB default charset=utf8mb4;

create table if not exists `note_favorite` (
  `id` bigint primary key auto_increment,
  `note_id` bigint not null,
  `user_id` bigint not null,
                                               `create_time` datetime default current_timestamp,
                                               unique key `uk_note_favorite` (`note_id`, `user_id`),
                                               foreign key (`note_id`) references `note`(`id`),
  foreign key (`user_id`) references `user`(`id`)
) engine=InnoDB default charset=utf8mb4;

create table if not exists `note_attachment` (
  `id` bigint primary key auto_increment,
  `user_id` bigint not null,
  `original_name` varchar(255) not null,
  `stored_name` varchar(255) not null,
  `storage_path` varchar(500) not null,
  `file_url` varchar(500) not null,
  `content_type` varchar(120) not null,
  `file_type` varchar(20) not null,
  `file_size` bigint not null,
  `create_time` datetime default current_timestamp,
  `update_time` datetime default current_timestamp on update current_timestamp,
  index `idx_note_attachment_user` (`user_id`, `create_time`),
  index `idx_note_attachment_type` (`file_type`),
  foreign key (`user_id`) references `user`(`id`)
) engine=InnoDB default charset=utf8mb4;

create table if not exists `note_attachment_reference` (
  `id` bigint primary key auto_increment,
  `attachment_id` bigint not null,
  `note_id` bigint not null,
  `create_time` datetime default current_timestamp,
  unique key `uk_note_attachment_reference` (`attachment_id`, `note_id`),
  index `idx_note_attachment_reference_note` (`note_id`),
  foreign key (`attachment_id`) references `note_attachment`(`id`) on delete cascade,
  foreign key (`note_id`) references `note`(`id`) on delete cascade
) engine=InnoDB default charset=utf8mb4;

create table if not exists `note_notification` (
  `id` bigint primary key auto_increment,
  `recipient_user_id` bigint not null,
                                                   `actor_user_id` bigint default null,
                                                   `type` varchar(40) not null,
                                                   `title` varchar(120) not null,
                                                   `content` varchar(500) default null,
                                                   `note_id` bigint default null,
                                                   `target_url` varchar(255) default null,
                                                   `read_flag` tinyint(1) default 0,
                                                   `create_time` datetime default current_timestamp,
                                                   `read_time` datetime default null,
                                                   index `idx_note_notification_recipient` (`recipient_user_id`, `read_flag`, `create_time`),
                                                   index `idx_note_notification_note` (`note_id`),
                                                   foreign key (`recipient_user_id`) references `user`(`id`),
                                                   foreign key (`actor_user_id`) references `user`(`id`),
                                                   foreign key (`note_id`) references `note`(`id`) on delete cascade
) engine=InnoDB default charset=utf8mb4;

create table if not exists `note_comment` (
                                              `id` bigint primary key auto_increment,
                                              `note_id` bigint not null,
                                              `user_id` bigint not null,
                                              `content` varchar(1000) not null,
                                              `create_time` datetime default current_timestamp,
                                              `update_time` datetime default current_timestamp on update current_timestamp,
                                              index `idx_note_comment_note` (`note_id`, `create_time`),
                                              foreign key (`note_id`) references `note`(`id`) on delete cascade,
                                              foreign key (`user_id`) references `user`(`id`)
) engine=InnoDB default charset=utf8mb4;

create table if not exists `operation_log` (
                                               `id` bigint primary key auto_increment,
                                               `user_id` bigint not null,
                                               `module` varchar(50) not null,
                                               `operation` varchar(200) not null,
                                               `create_time` datetime default current_timestamp
) engine=InnoDB default charset=utf8mb4;

create table if not exists `note_template` (
                                               `id` bigint primary key auto_increment,
                                               `user_id` bigint default null,
                                               `name` varchar(100) not null,
                                               `description` varchar(500) default null,
                                               `content` longtext,
                                               `html_content` longtext,
                                               `tags` varchar(500) default null,
                                               `category` varchar(50) default 'General',
                                               `is_system` tinyint(1) default 0,
                                               `create_time` datetime default current_timestamp,
                                               `update_time` datetime default current_timestamp on update current_timestamp,
                                               index `idx_note_template_user` (`user_id`),
                                               index `idx_note_template_system` (`is_system`, `category`),
                                               foreign key (`user_id`) references `user`(`id`)
) engine=InnoDB default charset=utf8mb4;

