INSERT IGNORE INTO `note` (`id`, `user_id`, `folder_id`, `title`, `content`, `html_content`, `tags`) VALUES
                                                                                                         (3001, 1001, 2001, 'Q2 版本路线图', '本季度主线放在收藏、分享、图谱三项能力，四月先稳住文件夹和回收站体验，五月补协作细节，六月准备演示版。验收标准是新用户十分钟内能完成创建、分类、分享一条笔记。', '<h2>Q2 版本路线图</h2><p>本季度主线放在收藏、分享、图谱三项能力，四月先稳住文件夹和回收站体验，五月补协作细节，六月准备演示版。验收标准是新用户十分钟内能完成创建、分类、分享一条笔记。</p>', '产品,roadmap,优先级'),
                                                                                                         (3002, 1001, 2001, '用户反馈摘录', '最近一周用户集中反馈三件事：文件夹树太高、关系选择不方便、提示消息位置不美观。下一轮改动优先做折叠、搜索和统一消息样式，避免继续堆功能导致可用性下降。', '<h2>用户反馈摘录</h2><p>最近一周用户集中反馈三件事：文件夹树太高、关系选择不方便、提示消息位置不美观。下一轮改动优先做折叠、搜索和统一消息样式，避免继续堆功能导致可用性下降。</p>', '用户反馈,体验,迭代'),
                                                                                                         (3003, 1001, 2002, 'Spring Boot 接口分层约定', '控制层只做参数校验和响应封装，服务层处理权限与事务，Mapper 层只保留明确的数据库操作。涉及分享、收藏、协作者等能力时，统一在服务层做访问控制，避免前端绕过规则。', '<h2>Spring Boot 接口分层约定</h2><p>控制层只做参数校验和响应封装，服务层处理权限与事务，Mapper 层只保留明确的数据库操作。涉及分享、收藏、协作者等能力时，统一在服务层做访问控制，避免前端绕过规则。</p>', 'SpringBoot,架构,代码规范'),
                                                                                                         (3004, 1001, 2002, '笔记删除链路排查', '删除文件夹前必须先处理文件夹下的已删除笔记，否则会被 note 表上的外键拦住。后续需要把 folder 删除逻辑拆成检查、解绑、删除三个步骤，并补一条集成测试防回归。', '<h2>笔记删除链路排查</h2><p>删除文件夹前必须先处理文件夹下的已删除笔记，否则会被 note 表上的外键拦住。后续需要把 folder 删除逻辑拆成检查、解绑、删除三个步骤，并补一条集成测试防回归。</p>', 'MySQL,事务,排障'),
                                                                                                         (3005, 1001, 2003, '文件夹树交互优化草案', '左侧树默认只展开一级，超过高度时使用内部滚动，同时给常用操作留固定区域。对于大量文件夹的场景，搜索结果要高亮匹配路径，并允许直接定位到节点。', '<h2>文件夹树交互优化草案</h2><p>左侧树默认只展开一级，超过高度时使用内部滚动，同时给常用操作留固定区域。对于大量文件夹的场景，搜索结果要高亮匹配路径，并允许直接定位到节点。</p>', 'Vue3,交互,性能'),
                                                                                                         (3006, 1001, 2003, '懒加载与拆包记录', '图谱、富文本、协作相关模块体积都偏大，首屏只保留基础工作台，图谱和编辑器走按路由懒加载。打包后重点盯 vendor-element、editor、echarts 三个 chunk 的体积变化。', '<h2>懒加载与拆包记录</h2><p>图谱、富文本、协作相关模块体积都偏大，首屏只保留基础工作台，图谱和编辑器走按路由懒加载。打包后重点盯 vendor-element、editor、echarts 三个 chunk 的体积变化。</p>', 'Vite,性能,前端工程化'),
                                                                                                         (3007, 1001, 2004, '协作者权限说明', 'OWNER 可以转授协作者、移动笔记和删除内容，EDIT 可以修改正文但不能改归属文件夹，READ 只能查看和收藏。权限说明要直接落到页面上，避免用户误以为协作等于完全共享。', '<h2>协作者权限说明</h2><p>OWNER 可以转授协作者、移动笔记和删除内容，EDIT 可以修改正文但不能改归属文件夹，READ 只能查看和收藏。权限说明要直接落到页面上，避免用户误以为协作等于完全共享。</p>', '协作,权限,文档'),
                                                                                                         (3008, 1001, 2004, '每日站会待办', '今天要确认三件事：收藏入口是否覆盖文件夹页和编辑页、图谱节点颜色是否可配置、后端定时缓存是否已可观测。下午五点前同步风险，避免问题拖到联调阶段再暴露。', '<h2>每日站会待办</h2><p>今天要确认三件事：收藏入口是否覆盖文件夹页和编辑页、图谱节点颜色是否可配置、后端定时缓存是否已可观测。下午五点前同步风险，避免问题拖到联调阶段再暴露。</p>', '团队,管理,同步'),
                                                                                                         (3009, 1001, 2005, '本周技术复盘', '这周最大的收益是先补验证再继续开发，很多交互问题只有在真实页面里才能暴露。下周继续减少重复状态和隐式依赖，尤其是折叠面板和文件夹树之间的联动问题。', '<h2>本周技术复盘</h2><p>这周最大的收益是先补验证再继续开发，很多交互问题只有在真实页面里才能暴露。下周继续减少重复状态和隐式依赖，尤其是折叠面板和文件夹树之间的联动问题。</p>', '复盘,效率,工程'),
                                                                                                         (3010, 1001, 2005, '下周个人学习清单', '重点补三块内容：Spring 事务传播、WebSocket 弱网重连策略、ECharts 大图渲染优化。学习目标不是只看文档，而是结合当前项目各写一个最小验证样例。', '<h2>下周个人学习清单</h2><p>重点补三块内容：Spring 事务传播、WebSocket 弱网重连策略、ECharts 大图渲染优化。学习目标不是只看文档，而是结合当前项目各写一个最小验证样例。</p>', '学习,AI,计划'),
                                                                                                         (3011, 1002, 2006, '操作系统进程调度重点', '期末重点放在时间片轮转、优先级调度和死锁条件这三块，老师经常把概念题和案例题混着出。复习时要用表格对比响应时间、吞吐量和适用场景，避免背概念时串题。', '<h2>操作系统进程调度重点</h2><p>期末重点放在时间片轮转、优先级调度和死锁条件这三块，老师经常把概念题和案例题混着出。复习时要用表格对比响应时间、吞吐量和适用场景，避免背概念时串题。</p>', '操作系统,课程,期末'),
                                                                                                         (3012, 1002, 2006, '数据库事务隔离总结', '可重复读能解决脏读和不可重复读，但幻读还需要结合间隙锁理解。面试回答时不要只背定义，最好带一个转账或库存的实际例子，说明为什么需要事务。', '<h2>数据库事务隔离总结</h2><p>可重复读能解决脏读和不可重复读，但幻读还需要结合间隙锁理解。面试回答时不要只背定义，最好带一个转账或库存的实际例子，说明为什么需要事务。</p>', '数据库,课程,MySQL'),
                                                                                                         (3013, 1002, 2007, '双指针常见题型', '双指针题先判断数组是否有序，再决定使用对撞指针还是快慢指针。刷题时把移除元素、盛最多水的容器、三数之和放一起做，能更快形成模板感。', '<h2>双指针常见题型</h2><p>双指针题先判断数组是否有序，再决定使用对撞指针还是快慢指针。刷题时把移除元素、盛最多水的容器、三数之和放一起做，能更快形成模板感。</p>', '算法,双指针,LeetCode'),
                                                                                                         (3014, 1002, 2007, '动态规划模板整理', '动态规划先写状态定义，再补状态转移，最后确定初始化和遍历顺序。最近总是卡在子序列问题，后面要把最长递增子序列和编辑距离再各写一遍。', '<h2>动态规划模板整理</h2><p>动态规划先写状态定义，再补状态转移，最后确定初始化和遍历顺序。最近总是卡在子序列问题，后面要把最长递增子序列和编辑距离再各写一遍。</p>', '算法,动态规划,面试'),
                                                                                                         (3015, 1002, 2008, 'Java 八股自我梳理', '集合、并发、JVM 是高频区域，回答时要把概念、应用场景和常见坑串起来。HashMap 不能只说数组加链表，要补充红黑树阈值和线程安全风险。', '<h2>Java 八股自我梳理</h2><p>集合、并发、JVM 是高频区域，回答时要把概念、应用场景和常见坑串起来。HashMap 不能只说数组加链表，要补充红黑树阈值和线程安全风险。</p>', 'Java,面试,后端'),
                                                                                                         (3016, 1002, 2008, '项目经历 STAR 版', '讲项目时先交代背景和目标，再说自己负责的模块，最后一定要用数据说明结果。知识管理系统这个项目可以重点讲文件夹分类、全文检索和协作权限三个模块。', '<h2>项目经历 STAR 版</h2><p>讲项目时先交代背景和目标，再说自己负责的模块，最后一定要用数据说明结果。知识管理系统这个项目可以重点讲文件夹分类、全文检索和协作权限三个模块。</p>', '求职,面试,项目'),
                                                                                                         (3017, 1002, 2009, '推荐系统论文速记', '这篇论文把召回、粗排、精排拆成三级结构，优点是线上延迟更稳定，缺点是特征工程成本高。后续可以重点看它在冷启动阶段如何用内容特征补充行为数据。', '<h2>推荐系统论文速记</h2><p>这篇论文把召回、粗排、精排拆成三级结构，优点是线上延迟更稳定，缺点是特征工程成本高。后续可以重点看它在冷启动阶段如何用内容特征补充行为数据。</p>', '论文,推荐系统,机器学习'),
                                                                                                         (3018, 1002, 2009, 'RAG 检索增强阅读摘录', 'RAG 的关键不是把模型换大，而是把切片、召回和重排做准。做课程汇报时可以举知识库问答的例子，说明为什么召回质量直接决定最终回答的可信度。', '<h2>RAG 检索增强阅读摘录</h2><p>RAG 的关键不是把模型换大，而是把切片、召回和重排做准。做课程汇报时可以举知识库问答的例子，说明为什么召回质量直接决定最终回答的可信度。</p>', 'AI,论文,RAG'),
                                                                                                         (3019, 1002, 2010, '本周开销记录', '这周主要开销是食堂、打印资料和一次面试路费，控制得还算稳。下周开始把不必要的外卖降下来，目标是把每周预算控制在三百以内。', '<h2>本周开销记录</h2><p>这周主要开销是食堂、打印资料和一次面试路费，控制得还算稳。下周开始把不必要的外卖降下来，目标是把每周预算控制在三百以内。</p>', '生活,记账,计划'),
                                                                                                         (3020, 1002, 2010, '四月作息调整计划', '最近熬夜刷题效率并不高，准备改成早起复习数据库和操作系统，晚上只做一套算法题。周末至少安排半天休息，不然面试前很容易状态下滑。', '<h2>四月作息调整计划</h2><p>最近熬夜刷题效率并不高，准备改成早起复习数据库和操作系统，晚上只做一套算法题。周末至少安排半天休息，不然面试前很容易状态下滑。</p>', '习惯,健康,生活'),
                                                                                                         (3021, 1003, 2011, '华东区客户回访记录', '本周回访的三家客户里，两家对知识图谱功能感兴趣，但都担心首次整理成本偏高。下次沟通要重点演示模板导入和文件夹归档，降低他们的试用门槛。', '<h2>华东区客户回访记录</h2><p>本周回访的三家客户里，两家对知识图谱功能感兴趣，但都担心首次整理成本偏高。下次沟通要重点演示模板导入和文件夹归档，降低他们的试用门槛。</p>', '客户,销售,跟进'),
                                                                                                         (3022, 1003, 2011, '续费风险名单', '目前风险最高的是使用频次低且团队人数少的客户，主要问题是没有形成固定使用习惯。需要提前安排一次回访，帮他们重新梳理使用场景和协作流程。', '<h2>续费风险名单</h2><p>目前风险最高的是使用频次低且团队人数少的客户，主要问题是没有形成固定使用习惯。需要提前安排一次回访，帮他们重新梳理使用场景和协作流程。</p>', '客户,续费,预警'),
                                                                                                         (3023, 1003, 2012, '五月直播活动清单', '直播主题定为团队知识沉淀实战，前一周完成海报、报名页和试讲。活动当天至少准备两个真实案例，避免全程讲功能导致转化率低。', '<h2>五月直播活动清单</h2><p>直播主题定为团队知识沉淀实战，前一周完成海报、报名页和试讲。活动当天至少准备两个真实案例，避免全程讲功能导致转化率低。</p>', '活动,直播,执行'),
                                                                                                         (3024, 1003, 2012, '社群裂变复盘', '上次裂变活动报名量不错，但进群后的留存偏低，问题出在欢迎话术太像广告。后面要把群内前三天的内容改成工具清单和实际模板，提高留下来的理由。', '<h2>社群裂变复盘</h2><p>上次裂变活动报名量不错，但进群后的留存偏低，问题出在欢迎话术太像广告。后面要把群内前三天的内容改成工具清单和实际模板，提高留下来的理由。</p>', '活动,增长,复盘'),
                                                                                                         (3025, 1003, 2013, '短视频选题库', '最近表现较好的选题都更贴近日常办公，比如会议纪要整理、项目交接、知识图谱串联资料。后面每周至少补十条选题，并按痛点、场景、结果三个维度归类。', '<h2>短视频选题库</h2><p>最近表现较好的选题都更贴近日常办公，比如会议纪要整理、项目交接、知识图谱串联资料。后面每周至少补十条选题，并按痛点、场景、结果三个维度归类。</p>', '内容,短视频,选题'),
                                                                                                         (3026, 1003, 2013, '周报标题模板', '高打开率标题通常包含一个明确场景和一个可量化结果，例如团队协作效率提升三成。周报选题不要只写流水账，每篇都要有一个能被记住的核心结论。', '<h2>周报标题模板</h2><p>高打开率标题通常包含一个明确场景和一个可量化结果，例如团队协作效率提升三成。周报选题不要只写流水账，每篇都要有一个能被记住的核心结论。</p>', '内容,写作,模板'),
                                                                                                         (3027, 1003, 2014, '渠道投放周报', '本周信息流带来的注册量最高，但付费转化还是来自老用户转介绍。下周继续压缩低质量渠道预算，把更多资源放到直播和老带新活动上。', '<h2>渠道投放周报</h2><p>本周信息流带来的注册量最高，但付费转化还是来自老用户转介绍。下周继续压缩低质量渠道预算，把更多资源放到直播和老带新活动上。</p>', '数据,投放,ROI'),
                                                                                                         (3028, 1003, 2014, '用户留存异常排查', '最近七日留存突然下降，初步判断和新手引导完成率偏低有关。需要和产品一起看埋点漏斗，确认是入口变更、性能问题还是内容表达不清。', '<h2>用户留存异常排查</h2><p>最近七日留存突然下降，初步判断和新手引导完成率偏低有关。需要和产品一起看埋点漏斗，确认是入口变更、性能问题还是内容表达不清。</p>', '数据,留存,排查'),
                                                                                                         (3029, 1003, 2015, '新同学入职 SOP', '入职第一周先完成产品体验、素材库熟悉和客户案例学习，第二周开始跟一个小型活动。所有模板、话术和数据看板入口都要集中在一个文件夹里，减少新人找资料的时间。', '<h2>新同学入职 SOP</h2><p>入职第一周先完成产品体验、素材库熟悉和客户案例学习，第二周开始跟一个小型活动。所有模板、话术和数据看板入口都要集中在一个文件夹里，减少新人找资料的时间。</p>', 'SOP,培训,流程'),
                                                                                                         (3030, 1003, 2015, '客诉升级处理流程', '遇到权限、数据丢失、导出失败等高风险问题时，客服要在十分钟内完成归类并同步研发。所有升级客诉必须记录时间线和处理结果，方便后续做复盘和标准化。', '<h2>客诉升级处理流程</h2><p>遇到权限、数据丢失、导出失败等高风险问题时，客服要在十分钟内完成归类并同步研发。所有升级客诉必须记录时间线和处理结果，方便后续做复盘和标准化。</p>', 'SOP,客服,流程'),
                                                                                                         (3031, 1004, 2016, '访谈提纲：新手用户 onboarding', '重点想验证三件事：第一次进入后是否理解文件夹用途、是否能快速找到创建笔记入口、是否知道分享和协作的区别。访谈时少问喜欢不喜欢，多追问实际卡在哪里。', '<h2>访谈提纲：新手用户 onboarding</h2><p>重点想验证三件事：第一次进入后是否理解文件夹用途、是否能快速找到创建笔记入口、是否知道分享和协作的区别。访谈时少问喜欢不喜欢，多追问实际卡在哪里。</p>', '用户研究,访谈,新手引导'),
                                                                                                         (3032, 1004, 2016, '核心角色画像更新', '目前可以先明确三类核心用户：个人知识整理者、小团队协作者、需要结构化沉淀的项目经理。后续所有首页表达都围绕这三类角色写，不再用泛化描述。', '<h2>核心角色画像更新</h2><p>目前可以先明确三类核心用户：个人知识整理者、小团队协作者、需要结构化沉淀的项目经理。后续所有首页表达都围绕这三类角色写，不再用泛化描述。</p>', '用户研究,画像,用户分层'),
                                                                                                         (3033, 1004, 2017, '待排期需求池', '当前待排期需求里，搜索文件夹、收藏共享笔记、图谱节点配色都属于高频反馈。先做能明显降低操作成本的能力，再考虑视觉层面的增量优化。', '<h2>待排期需求池</h2><p>当前待排期需求里，搜索文件夹、收藏共享笔记、图谱节点配色都属于高频反馈。先做能明显降低操作成本的能力，再考虑视觉层面的增量优化。</p>', '需求管理,优先级,产品'),
                                                                                                         (3034, 1004, 2017, 'P1 问题清单', '当前 P1 级问题包括删除空文件夹报外键错误、折叠面板联动异常、协作者区域展示不稳定。问题修复后要逐条补回归用例，避免后面版本再次出现。', '<h2>P1 问题清单</h2><p>当前 P1 级问题包括删除空文件夹报外键错误、折叠面板联动异常、协作者区域展示不稳定。问题修复后要逐条补回归用例，避免后面版本再次出现。</p>', '缺陷,产品,排期'),
                                                                                                         (3035, 1004, 2018, '首页改版原型说明', '首页改版的重点不是塞更多入口，而是把最近使用、文件夹、收藏和灵感卡片排出优先级。视觉上保持清爽，但操作路径必须比旧版更短。', '<h2>首页改版原型说明</h2><p>首页改版的重点不是塞更多入口，而是把最近使用、文件夹、收藏和灵感卡片排出优先级。视觉上保持清爽，但操作路径必须比旧版更短。</p>', '原型,Figma,交互'),
                                                                                                         (3036, 1004, 2018, '图谱配色方案备选', '图谱默认配色需要兼顾层次感和可读性，节点过多时不能只靠随机颜色。方案上保留产品预设，同时允许用户按标签或节点类别自定义主色。', '<h2>图谱配色方案备选</h2><p>图谱默认配色需要兼顾层次感和可读性，节点过多时不能只靠随机颜色。方案上保留产品预设，同时允许用户按标签或节点类别自定义主色。</p>', '设计,图谱,配色'),
                                                                                                         (3037, 1004, 2019, '版本发布检查单', '上线前必须确认迁移脚本、核心接口、分享页、收藏链路和图谱展示都已验收。检查单不要只写模块名，要写成可以逐项勾掉的动作列表。', '<h2>版本发布检查单</h2><p>上线前必须确认迁移脚本、核心接口、分享页、收藏链路和图谱展示都已验收。检查单不要只写模块名，要写成可以逐项勾掉的动作列表。</p>', '发布,上线,检查'),
                                                                                                         (3038, 1004, 2019, '灰度发布沟通稿', '这次灰度先覆盖内部团队和十个试用客户，重点观察收藏使用率和文件夹搜索命中率。对外沟通坚持一个原则：先说明新增价值，再说明注意事项。', '<h2>灰度发布沟通稿</h2><p>这次灰度先覆盖内部团队和十个试用客户，重点观察收藏使用率和文件夹搜索命中率。对外沟通坚持一个原则：先说明新增价值，再说明注意事项。</p>', '发布,沟通,风险'),
                                                                                                         (3039, 1004, 2020, '一对一沟通纪要', '本周和研发、运营分别做了一次一对一，大家都希望需求说明更具体，减少开发中途反复确认。后面需求文档里要补充目标用户、边界条件和验收口径。', '<h2>一对一沟通纪要</h2><p>本周和研发、运营分别做了一次一对一，大家都希望需求说明更具体，减少开发中途反复确认。后面需求文档里要补充目标用户、边界条件和验收口径。</p>', '管理,沟通,团队'),
                                                                                                         (3040, 1004, 2020, '设计评审关注点', '评审时重点看三个方面：是否减少了用户操作步数、是否保持组件行为一致、异常状态是否有清晰反馈。视觉漂亮很重要，但不能建立在交互成本变高的前提上。', '<h2>设计评审关注点</h2><p>评审时重点看三个方面：是否减少了用户操作步数、是否保持组件行为一致、异常状态是否有清晰反馈。视觉漂亮很重要，但不能建立在交互成本变高的前提上。</p>', '评审,设计系统,团队');
